function autoOpenTab(){var e;e=document.getElementsByClassName("tab__item"),e[0].style.display="block"}function openTab(e,t){var a,l,s;for(l=document.getElementsByClassName("tab__item"),a=0;a<l.length;a++)l[a].style.display="none";for(s=document.getElementsByClassName("tab__links"),a=0;a<s.length;a++)s[a].className=s[a].className.replaceAll(" active",""),document.getElementById(t).style.display="block",e.currentTarget.className+=" active"}function openTabTarget(e,t){var a,l=document.getElementsByClassName("tab__item"),s=document.getElementsByClassName("tab__links");for(a=0;a<l.length;a++)l[a].style.display="none";for(a=0;a<s.length;a++)s[a].classList.remove("active");document.getElementById(e).style.display="block",document.getElementById(t).classList.add("active")}autoOpenTab();